"""
Standalone patch — writes mkt-context for Isaiah 37-40.
Run: python3 scripts/zc-context-isaiah-37-40-patch.py
Chapters: 37 (38v), 38 (22v), 39 (8v), 40 (31v) = 99 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "37": {
    "1": "<p>Isaiah 37:1 describes Hezekiah's response to the Rabshakeh's speech — the precise posture of covenant mourning: 'vayehi kishmoa hammelek Chizkiyahu vayiqra et-begadaiv, and when King Hezekiah heard he tore his garments.' Three actions: tearing garments (the grief-response of Gen 37:29; 2 Sam 3:31; 2 Kgs 22:11), covering with sackcloth (the rough mourning-garment), and entering 'the house of the LORD' (the temple). The last action is the theologically decisive one: Hezekiah goes to YHWH's house rather than to the war-council. The contrast with Ahaz (7:2-9) is complete — Ahaz's heart shook like trees in the wind; Hezekiah goes directly to YHWH. The temple-entry as crisis-response enacts the theology of Ps 46 ('God is our refuge and strength, an ever-present help in trouble') concretely.</p>",
    "2": "<p>'He sent Eliakim the palace administrator, Shebna the royal secretary, and the senior priests — all of them covered in sackcloth — to the prophet Isaiah son of Amoz' — the prophetic consultation: Hezekiah sends the same three officials (Eliakim, Shebna, Joah — from 36:3, though Joah is replaced by senior priests here) to Isaiah. The sackcloth on the officials = the official state of mourning and humiliation before YHWH extending to the entire royal household. 'The prophet Isaiah son of Amoz' — the formal prophetic title emphasizes that the inquiry is being directed to YHWH's authorized spokesperson. The contrast with 39:3-4 (where Isaiah comes uninvited to interrogate Hezekiah about the Babylonian envoys) shows two postures: crisis-prayer reaching out to YHWH's prophet, and pride-display that the prophet must correct.</p>",
    "3": "<p>'Thus says Hezekiah: This day is a day of distress, rebuke, and disgrace. We are like a woman in labor who has no strength to deliver' — Hezekiah's message through the officials contains three covenant-crisis terms: tsarah (distress/trouble), tochechah (rebuke/correction), and netsah (disgrace/contempt). The labor-pain metaphor: 'ki ba'u vanim ad-mishbar vekoach ayin leledah, for children have come to the birth-stool and there is no strength to give birth' — the image of 26:17-18 (which described Israel's failed birth as 'we gave birth to wind') repeated but now used as a cry for divine intervention rather than a description of failure. The 'children at the birth-stool with no strength to deliver' = the community in the crisis-moment of maximum vulnerability, needing YHWH to complete what human effort cannot.</p>",
    "4": "<p>'Perhaps the LORD your God will hear the words of Rabshakeh... and will rebuke those words. The LORD your God has heard them — so lift up a prayer for the remnant that survives' — the theological precision of Hezekiah's prayer-request: 'uly yishma YHWH Elohekha et-divrei Ravshaqeh, perhaps YHWH your God will hear the words of Rabshakeh' — the 'perhaps' (uly) is not doubt but the humility of not presuming on divine response. The key theological term: 'el-chai, the living God' — as opposed to the dead idols of the nations (37:19: 'they were not gods at all, only things men made'). Rabshakeh has treated YHWH as if he were a Hamath-deity who has already been defeated; Hezekiah corrects the category: YHWH is the living God who hears and acts. 'A prayer for the remnant' (tissah tefillah be'ad hasheri'it hannimsah, lift up a prayer for the surviving remnant) = the shear'it (remnant = the theological core of Isaiah's hope, 10:20-22; 11:11-16).</p>",
    "5": "<p>'So the servants of King Hezekiah came to Isaiah' — the brief transitional verse that is theologically loaded: the servants (avadei, the officials) of the king (hammelek) go to the prophet. The three-party structure: Hezekiah → officials → Isaiah → YHWH. The king uses intermediaries to reach the prophet who speaks for YHWH — the prophetic institution as the communication channel between the king and God. Isaiah's response (v6-7) does not require elaborate rituals or lengthy inquiry: it comes immediately and directly. The brevity of the exchange suggests that Isaiah had already received the divine word before being asked.</p>",
    "6": "<p>'Isaiah said to them: Say this to your master: Thus says the LORD — Do not be afraid of the words you have heard, with which the servants of the king of Assyria have reviled me' — the prophetic 'do not be afraid': 'ko-amar YHWH al-tira mippenei hadevarim, thus says YHWH: do not be afraid from before the words.' Al-tira (do not be afraid) is the standard divine comfort formula of the patriarchal narratives (Gen 15:1; 26:24; 46:3) and throughout Isaiah (7:4; 35:4; 40:9; 41:10-14; 43:1-5). Isaiah's oracle addresses Hezekiah through the officials — the same chain through which the request came. 'Which the servants of the king of Assyria have reviled me' (asher giddephu na'arei melek Ashshur oti, which the servants of the king of Assyria have spoken against me as blasphemy) — the key insight: Rabshakeh's speech was not merely against Hezekiah but against YHWH himself. The reviling (giddephu = to blaspheme/revile) makes the conflict YHWH's, not just Judah's.</p>",
    "7": "<p>'Watch — I will put a disturbing spirit in him so that he hears a rumor and returns to his own land, and I will bring him down by the sword in his own land' — the two-stage divine action against Sennacherib: (1) 'hineni noten bo ruach, behold I am putting a spirit in him' — the divine insertion of a ruach (spirit/wind = could be a spirit of delusion/disturbing, cf. 1 Sam 16:14: an evil spirit from YHWH troubled Saul) that makes Sennacherib receptive to a rumor (shemu'ah = a report/news). The rumor causes him to return home. (2) 'and I will bring him down by the sword in his own land' (vehippiltihu becherev be'artsoh) = the assassination of 37:38. The two divine acts are separated by 20 years historically (701 BCE siege, 681 BCE assassination) but presented as a unified divine plan. YHWH controls both the immediate strategic situation and the long-range personal fate of the emperor.</p>",
    "8": "<p>'Rabshakeh turned back and found the king of Assyria fighting at Libnah, for he had heard that the king had moved on from Lachish' — the logistical note: 'vayashov Ravshaqeh vayimsah et-melek Ashshur nilcham al-Livnah, Rabshakeh returned and found the king of Assyria fighting at Libnah.' Libnah (Tell Burna, approximately 5 miles northeast of Lachish) was the next target in the Assyrian sweep through Judah's fortified cities. 'For he had heard that the king had moved on from Lachish' (ki shama ki nasa milLakhish, for he heard that he had pulled up from Lachish) — the narrative detail confirming the historical reconstruction of Sennacherib's 701 BCE campaign: Lachish taken, army moved to Libnah, while simultaneously investing Jerusalem. The Assyrian military machine operating on multiple fronts.</p>",
    "9": "<p>'Then word reached Sennacherib about Tirhakah king of Cush: He has marched out to fight you. When Sennacherib heard it, he sent messengers again to Hezekiah' — the strategic context of the second letter: Tirhakah (Hebrew: Tirhaqa = the Pharaoh Taharka, who ruled Egypt 690-664 BCE as the last major 25th/Kushite Dynasty pharaoh). The chronological problem: in 701 BCE (Sennacherib's campaign), Taharka was approximately 12-20 years old and was a military commander, not yet king. He became king in 690 BCE. The historicity is defended by noting he was already a prominent military figure in 701 BCE, leading Egyptian forces. Alternatively, the text reflects a later editorial updating of his title to his eventual royal status. The strategic reality: the threat of Egyptian/Kushite intervention was the external factor that may have contributed to Sennacherib's decision to accept a tribute arrangement and withdraw rather than siege Jerusalem to the end.</p>",
    "10": "<p>'Say this to Hezekiah king of Judah: Do not let your God, in whom you are trusting, deceive you by saying that Jerusalem will not be given into the hand of the king of Assyria' — the second letter's core argument is identical to the first: 'Do not let your God deceive you' (al-yashia etkhah Elohekha asher attah boteach bo, do not let your God lead you astray, in whom you are trusting). Sennacherib attempts to use the Isaiah-oracle (that Jerusalem will not fall) as evidence of Hezekiah's deception by his own God. This is the inverse of the truth: YHWH is not deceiving Hezekiah — Sennacherib's own gods (Nisroch, 37:38) will not save him. The letter's use of 'in whom you are trusting' (boteach) echoes the batach vocabulary of the entire oracle-series (30:12, 15; 31:1; 36:4-9): trust rightly placed in YHWH is the answer to all the mis-trust oracles.</p>",
    "11": "<p>'You have certainly heard what the kings of Assyria have done to every land — they destroyed them completely. Do you think you alone will be delivered?' — the historical argument from Assyrian track record: 'hineh attah shamata asher asu malkhei Ashshur lekhol-ha'aratsot lehachariymam, behold you have heard what the kings of Assyria have done to all the lands, devoting them to destruction.' The herem (sacred destruction = the war-ban of total annihilation, the same term as YHWH's ban on Edom in 34:2) applied to every nation. The implied logic: the universality of Assyrian success means no exception is possible. But Isaiah's oracles have already answered this: YHWH planned the Assyrian conquests (37:26); he is not defeated when Hamath falls. Sennacherib treats history as the accumulation of Assyrian power; Isaiah treats the same history as the outworking of YHWH's plan.</p>",
    "12": "<p>'Did the gods of the nations rescue the peoples my fathers destroyed — Gozan, Haran, Rezeph, and the people of Eden who were in Telassar?' — the roll call of defeated nations and their gods: Gozan (modern Tell Halaf in NE Syria = the site of the Israelite exile from Samaria, 2 Kgs 17:6; 18:11); Haran (the city of Abraham's sojourn in NW Mesopotamia/modern Harran in SE Turkey = the site of pagan moon-god worship); Rezeph (Rasappa, an Assyrian administrative center in northern Syria); the people of Eden in Telassar (possibly the Bit-Adini tribe in the middle Euphrates region, conquered by Shalmaneser III). Each name represents a conquered people whose local deity failed to protect them. The list is intended as a comprehensive demonstration of divine impotence — but it carefully avoids listing YHWH's people among the failures, though Samaria is mentioned in 36:19.</p>",
    "13": "<p>'Where is the king of Hamath now? The king of Arphad? The king of the city of Sepharvaim, of Hena, and of Ivah?' — the political erasure of conquered kings: the 'where is' (ayeh) question = the rhetorical question of obliteration (cf. Job 14:10: 'But a man dies and is laid low; he breathes his last and is no more'). Hamath (conquered by Sargon II in 720 BCE when he deported the ruling class and replaced them with Assyrian settlers); Arphad (conquered by Tiglath-pileser III in 740 BCE, by Sargon II again in 720 BCE); Sepharvaim, Hena, Ivah (Assyrian-controlled cities in Syria and possibly Mesopotamia whose populations were resettled in Samaria, 2 Kgs 17:24). All these kings are not just defeated but erased — their kingdoms absorbed and eliminated as political entities. The implied question: Hezekiah, what makes Jerusalem different from Hamath?</p>",
    "14": "<p>'Hezekiah received the letter from the messengers and read it. Then he went up to the house of the LORD and spread it out before the LORD' — the climactic act of prayer: 'vayiqqach Chizkiyahu et-hasefarim miyyad hammalakhim vayiqra'em, Hezekiah received the letters from the hand of the messengers and read them.' Then: 'vayya'al bet YHWH vayifrosh oto Chizkiyahu lifnei YHWH, he went up to the house of YHWH and spread it out before YHWH.' The physical spreading of the enemy's letter before YHWH is one of the most vivid prayer-acts in the OT — making YHWH the audience of the enemy's arrogance, presenting the document directly to the divine King as an ambassador would present credentials. The prayer that follows (vv.15-20) is what the letter prompts. Hezekiah does not strategize, does not consult generals — he spreads the letter before YHWH.</p>",
    "15": "<p>'And Hezekiah prayed to the LORD' — the simple transitional verse between the letter-spreading and the actual prayer. 'Vayitpallel Chizkiyahu el-YHWH, and Hezekiah prayed to YHWH.' The palal (to pray/intercede = to put oneself before a judge as a mediator or intercessor) directed specifically to YHWH. The prayer of vv.16-20 is one of the great OT prayer-texts, structured as: (1) address of YHWH as universal creator and sole God (v16), (2) petition for YHWH to hear and see (v17), (3) acknowledgment of Assyrian historical reality (vv18-19), (4) theological analysis of why Assyrian victory does not disprove YHWH's power (v19b), (5) the petition for deliverance (v20), and (6) the stated purpose: universal recognition of YHWH's uniqueness (v20b).</p>",
    "16": "<p>'O LORD of hosts, God of Israel, enthroned above the cherubim — you alone are God over all the kingdoms of the earth. You made heaven and earth' — the opening address of Hezekiah's prayer grounds the petition in the most comprehensive theology possible: 'YHWH tseva'ot Elohei Yisrael yoshev hakeruvim, YHWH of hosts, God of Israel, enthroned on the cherubim.' YHWH's throne on the cherubim = the Ark of the Covenant in the Holy of Holies (1 Sam 4:4; 2 Sam 6:2; Ps 80:1; 99:1) — Hezekiah prays in the physical presence of YHWH's throne. 'Attah-hu ha'Elohim levaddekha lekhol mamlekhot ha'arets, you alone are God over all the kingdoms of the earth' — the monotheistic claim explicitly applied geopolitically: not merely Israel's god but the god of all kingdoms (contra Rabshakeh's comparative polytheism). 'You made heaven and earth' (attah asita et-hashamayim ve'et-ha'arets) = the creation claim as the ground of universal sovereignty.</p>",
    "17": "<p>'Incline your ear, LORD, and hear; open your eyes, LORD, and see; hear all the words Sennacherib has sent to mock the living God' — the petition for divine attention: 'hate YHWH aznekhah ushema, incline your ear, YHWH, and hear.' The physical anthropomorphisms of divine attention: 'incline your ear' (the posture of attentive listening) and 'open your eyes' (the posture of attentive looking). The same anthropomorphisms appear in 2 Kgs 19:16; Ps 31:2; 71:2; Dan 9:18. The object of YHWH's seeing: 'all the words Sennacherib has sent to mock the living God' (et-kol-divrei Sancherib asher shalach lecherapa Elohim chay, all the words of Sennacherib which he sent to reproach the living God). The el-chay (living God) is the decisive category: Sennacherib's gods are dead things (v19: 'wood and stone'); YHWH is the living God whose life means action, response, and intervention.</p>",
    "18": "<p>'It is true, LORD, that the kings of Assyria have devastated all the nations and their lands' — the theological honesty of Hezekiah's prayer: 'amen YHWH hecherivu malkhei Ashshur et-kol-ha'aratsot ve'et-artsam, truly, LORD, the kings of Assyria have laid waste all the lands and their countries.' The amen (truly = the affirmation that what follows is reliable and true) acknowledges the empirical reality of Assyrian conquest without minimizing it. This is not denial of historical evidence but the refusal to interpret that evidence through Assyrian theology. Hezekiah is essentially agreeing with Sennacherib's facts (yes, he has destroyed nations) while disputing his interpretation (this does not mean YHWH cannot save Jerusalem). The prayer functions as a model of faith that engages reality rather than retreating into denial.</p>",
    "19": "<p>'And thrown their gods into the fire. For they were not gods at all, only things men made with their hands — wood and stone — so they were able to destroy them' — the theological explanation of why Assyrian success does not disprove divine power: 'venatenav et-elohehem ba'esh ki lo Elohim hemmah ki im-ma'aseh yedei adam ets va'even vayyeabbedum, and they have given their gods to the fire, for they were not gods but the work of human hands — wood and stone — so they destroyed them.' The idol-polemic: the gods of the nations were wooden and stone objects — they could be burned (wood) or smashed (stone). Their destruction proves they were never real deities. YHWH cannot be 'burned' or 'smashed' because he is the living God who created the wood and stone from which idols are made. The argument is identical to 40:18-20's idol polemic and 44:9-20's detailed satire.</p>",
    "20": "<p>'So now, LORD our God, deliver us from his hand, so that all the kingdoms of the earth may know that you, LORD, are God and you alone' — the petition for deliverance and its stated purpose: 'veat'ah YHWH Elohenu hoshi'enu miyyado, and now LORD our God save us from his hand.' The deliverance requested is not ultimately for Judah's benefit but for YHWH's universal reputation: 'lema'an yede'u kol-mamlekhot ha'arets ki-attah YHWH levaddekha, so that all the kingdoms of the earth may know that you, LORD, are God alone.' The universal-knowledge formula ('then they will know that I am YHWH') is the driving purpose of the prayer — YHWH's intervention in history is fundamentally missionary/evangelistic: the nations come to know who YHWH is through his acts. This is the most expansive possible motivation for prayer: not 'save us so we survive' but 'save us so the nations know you.'</p>",
    "21": "<p>'Then Isaiah son of Amoz sent word to Hezekiah: Thus says the LORD, the God of Israel: Because you have prayed to me about Sennacherib king of Assyria' — the divine response triggered by the prayer: 'az shalach Yesha'yahu ben-Amots el-Chizkiyahu, then Isaiah son of Amoz sent to Hezekiah.' The sending (shalach) of Isaiah's response = the prophetic oracle delivered in response to the prayer. The grounding of the oracle: 'ya'an hitpalaleta elai al-Sancherib melek Ashshur, because you have prayed to me about Sennacherib.' The 'because you prayed' is the explicit connection between the petition and the response — the prayer occasioned the oracle. This establishes a model: YHWH's prophetic word comes in response to honest prayer that spreads the enemy's threat before him. The oracle that follows (vv.22-35) is the most extensive prophetic response to prayer in Isaiah.</p>",
    "22": "<p>'This is the word the LORD has spoken concerning him: The virgin daughter of Zion despises you and laughs you to scorn; daughter Jerusalem shakes her head at your retreating back' — the taunt-song against Sennacherib opens with Zion's contempt: 'zeh haddavar asher dibber YHWH alaiv, this is the word which YHWH has spoken against him.' The 'virgin daughter of Zion' (betulat bat-Tsiyon = the image of Jerusalem as a young woman not yet violated by enemy conquest; the 'daughter of Zion' personification appears throughout the prophets for Jerusalem) 'despises you' (baza, holds in contempt). 'Shakes her head' (nud rosh, shaking the head in mockery = the gesture of contemptuous dismissal, Ps 22:7; Lam 2:15) 'at your retreating back' (acareykha, behind you = as you flee). The prophetic oracle reverses the power dynamic: the conqueror is the object of derision, not the conquered.</p>",
    "23": "<p>'Whom did you mock and blaspheme? Against whom did you raise your voice and lift your eyes with pride? Against the Holy One of Israel' — the charge reframed: 'et-mi cherefa ugedafta, whom did you reproach and blaspheme?' The cherefa (reproach/mockery) and gadaf (blasphemy = the deliberate defaming of YHWH's character) = the technical language of sacrilege. 'Against whom did you raise your voice and lift your eyes with pride?' (ve'al-mi harimmota qol vatissa merom einekhah, against whom did you raise your voice and lift your eyes in exaltation?) — the eye-lifting to exaltation = the pride gesture of 2:11 ('the eyes of the arrogant will be humbled'). The answer: 'el-qedosh Yisrael, against the Holy One of Israel' — Isaiah's distinctive divine title, invoked here at the climax of the confrontation. Sennacherib's boasts were not merely political; they were theological acts of defiance against the specific character of YHWH as the holy one.</p>",
    "24": "<p>'By your servants you mocked the Lord and boasted: With my vast forces of chariots I have scaled the mountain heights, the far slopes of Lebanon; I have felled its tallest cedars and finest cypresses; I reached its highest summit, its deepest forests' — YHWH quotes Sennacherib's boasting back to him: 'beyad avadekhah cherafa Adonai, by your servants you mocked the Lord.' The oracle then quotes Sennacherib's actual military boasts — the kind found verbatim in Assyrian royal annals: 'with the multitude of my chariots I went up to the heights of the mountains, to the far side of Lebanon' (the mountain-heights = the boast of having conquered the most difficult terrain; Lebanon = the cedar-forests as a symbol of the most challenging, remote territory). Sennacherib's annals contain exactly this kind of topographic boasting: mountains, forests, heights scaled and conquered. The cedar-cutting (I have felled its tallest cedars) = the destruction of Lebanon's forests for military construction and as a symbol of conquest of nature itself.</p>",
    "25": "<p>'I dug wells and drank water; with the tread of my feet I dried up all the streams of Egypt' — the continuation of Sennacherib's boasting attributed to him by YHWH: 'ani kariti veshatiythi mayim, I dug and drank waters' — the practical military achievement of creating water supply in arid territory. 'With the sole of my foot I dried up all the rivers of Egypt' (ve'echerav bekhaph padami kol-yeore matsur, and I dried up with the sole of my foot all the streams of Egypt) — the hyperbolic military claim: even Egypt's Nile-system dried before Sennacherib's march. This is the kind of cosmic-scale boasting that Assyrian royal inscriptions actually contain: claiming to have conquered nature alongside nations. YHWH records Sennacherib's own words to use them as evidence of his arrogance in the judgment (v27-29).</p>",
    "26": "<p>'Have you not heard? I planned this long ago; in ancient times I formed it; now I have brought it to pass, that you should turn fortified cities into heaps of ruins' — the theological bombshell of the oracle: 'halo shamata lemerachok otah asiti, have you not heard? From long ago I planned it.' YHWH claims credit for Assyria's conquests — they were his plan from antiquity, not Sennacherib's achievement. 'Mimei qedem yetsartiha attah hevatiha, from ancient days I formed it; now I have brought it to pass.' The contrast: Sennacherib thinks he is acting on his own initiative; YHWH reveals that the entire Assyrian imperial project was YHWH's ancient plan (cf. 10:5-6: 'Assyria, the rod of my anger, in whose hand is the club of my wrath; I sent him against a godless nation'). 'That you should turn fortified cities into heaps of ruins' (lelashum gal nizharot bitstsurot battsurot, to turn fortified cities into heaps, desolate ruins) = the destruction was YHWH's intended outcome, accomplished through Sennacherib's unwitting service.</p>",
    "27": "<p>'So their inhabitants had little strength; they were shattered and ashamed; they were like plants of the field, like tender shoots, like grass on the rooftops — blighted before it could grow' — the condition of the nations that fell before Assyria: 'veyosheveihen qetsre yad chatu vayvoshu, their inhabitants were short of hand (powerless), shattered and ashamed.' Their powerlessness was YHWH's design — the nations that Sennacherib destroyed were already made weak by YHWH's plan, enabling the Assyrian conquest. The four vegetation images for their frailty: 'plants of the field' (esev sadeh), 'tender green shoots' (yaraq deshe), 'grass on the rooftops' (chatsir gagot) — rooftop grass is particularly ephemeral: it sprouts in the clay mortar but withers almost immediately because the roots have nowhere to go (Ps 129:6-7: 'May they be like grass on the roof, which withers before it can grow; with it the reaper cannot fill his hands'). 'Blighted before it could grow' (gedudah lifnei qamah = cut down before it stood up).</p>",
    "28": "<p>'But I know your dwelling place, your going out and coming in, and your rage against me' — YHWH's omniscient surveillance of Sennacherib: 'veshivtekha vetsetekha uvoa'akha yadati, your sitting down and your going out and coming in I know.' The three activities — sitting (shevet = dwelling/resting in place), going out (tset = departing), coming in (bo = entering) — together describe the complete cycle of movement and rest that makes up a life. YHWH knows all of it — not just the public military campaigns but the private dwelling. The same comprehensive knowing applies to Israel (Ps 139:2-3: 'you know when I sit and when I rise; you perceive my thoughts from afar; you discern my going out and my lying down; you are familiar with all my ways'). 'And your rage against me' (ve'et-hitraggezkha elay) = YHWH is specifically aware of Sennacherib's religious defiance, not merely his military movements.</p>",
    "29": "<p>'Because your rage against me and your arrogance have reached my ears, I will put my hook through your nose and my bit between your lips, and I will send you back the way you came' — the divine counter-plan: 'ya'an hit-raggezkha elay veshaloankha ala be'ozanai, because of your raging against me and your arrogance coming up into my ears.' The sensory detail of YHWH 'hearing' the arrogance in his ears = the divine patience waiting until the full measure of arrogance is registered. The punishment: 'vesamti chityi be'appekha uvimtomi bisefateykha, I will put my hook in your nose and my bit between your lips.' The hook-in-nose was the Assyrian image for controlling captive kings: the Lachish Reliefs and the Black Obelisk of Shalmaneser III depict Assyrian kings leading conquered rulers by hooks through their lips and rings through their noses. YHWH turns Assyria's own domination-imagery back on Sennacherib: the conqueror-of-kings is himself led by a nose-hook back the way he came.</p>",
    "30": "<p>'And this will be the sign for you: This year you will eat what grows on its own, and next year what springs up from that; but in the third year you will sow and reap, plant vineyards and eat their fruit' — the three-year agricultural recovery sign: 'vezeh lekha ha'ot, and this will be the sign to you.' Year 1: 'saphiach tochel, you will eat the volunteer-growth' (saphiach = the grain that grows from last year's fallen seeds without deliberate planting). Year 2: 'saphiach saphichah, you will eat the second-year volunteer' (the growth from the volunteer seed of year 1). Year 3: 'u'setem venetsartem, you will sow and reap' (the normal agricultural cycle restored). The three years reflects the reality of the 701 BCE invasion: the Assyrian presence disrupted normal agriculture for two seasons; by the third year the normal cycle could resume. The sign is ecological-historical: the time it takes for agriculture to recover from military disruption.</p>",
    "31": "<p>'And the remnant of the house of Judah that has escaped will once more take root downward and bear fruit upward' — the remnant-oracle of restoration: 'veyasef pelitat bet-Yehudah hannishot sharash lematah ve'asah peri lema'la, and the escaped remnant of the house of Judah will again take root downward and bear fruit upward.' The botanical metaphor of restoration: taking root (sharash = to be rooted, from shoresh = root) downward (lematah = toward the earth) and bearing fruit (asah peri) upward (lema'la = toward the sky). The taking-root before the fruit-bearing = the sequence of restoration: the invisible underground work of establishing covenant community must precede visible flourishing. The contrast with 27:6 ('in coming days Jacob will take root; Israel will blossom and sprout and fill the whole world with fruit') which looks further into the eschatological future.</p>",
    "32": "<p>'For a remnant will go out from Jerusalem, and survivors from Mount Zion. The zeal of the LORD of hosts will accomplish this' — the remnant-theology climax: 'ki miyYerushalayim tetse she'erit, for from Jerusalem will go out a remnant.' The she'erit (remnant = those left over after judgment) and palitah (escaped/survivors) going out from Jerusalem and Mount Zion = the covenant community continuing beyond the Assyrian crisis. The theological ground: 'qin'at YHWH tseva'ot ta'aseh zot, the zeal of YHWH of hosts will accomplish this.' The divine qin'ah (jealousy/zeal = the passionate, exclusive commitment of a covenant partner) as the guarantee of the remnant's survival. The same phrase appears in 9:7 for the Davidic messianic promise: YHWH's zeal guarantees both the remnant and the messianic heir.</p>",
    "33": "<p>'Therefore thus says the LORD concerning the king of Assyria: He will not enter this city, nor shoot an arrow into it, nor advance on it with a shield, nor build a siege ramp against it' — the specific military promises about Jerusalem's inviolability: 'al-ken ko-amar YHWH el-melek Ashshur, therefore thus says YHWH concerning the king of Assyria.' Four precise military non-actions: (1) 'lo yavo el-ha'ir hazot, he will not enter this city' = no capture; (2) 'velo-yore sham chets, he will not shoot an arrow there' = no archery assault; (3) 'velo-yeqademenah magen, he will not come before it with a shield' = no direct infantry assault with siege shields; (4) 'velo-yishpokh aleyhah sollalah, he will not pour out a siege-ramp against it' = no engineering approach. All four specific Assyrian siege techniques are explicitly excluded. Sennacherib's own annals confirm: he describes the siege but never claims Jerusalem's capture — all four non-events match the historical record.</p>",
    "34": "<p>'He will go back the same road he came. He will not enter this city, declares the LORD' — the repetition and reinforcement: 'badderekh asher-va bah yashuv, by the road he came he will return.' The return by the same road (not a conquering march through a defeated city) = the strategic retreat without victory. 'He will not enter this city, declares the LORD' (veel-ha'ir hazot lo yavo, and into this city he will not come, declares YHWH) — the repeated assurance is not redundant but emphatic: twice stating the same thing in ANE style creates an oath-like certainty (cf. Ps 121's fivefold repetition of YHWH 'keeping' Israel). The ne'um-YHWH (declares the LORD) = the prophetic authentication formula, marking the oracle as direct divine speech.</p>",
    "35": "<p>'For I will defend this city and save it — for my own sake and for the sake of my servant David' — the double motivation for Jerusalem's defense: 'vegannoti al-ha'ir hazot lehoshi'ah, and I will shield over this city to save it.' The two reasons: (1) 'Lemaan'i, for my own sake' = YHWH's own honor and identity (the same motivation Ezek 36:22-23 gives for the restoration: 'not for your sake but for the sake of my holy name'); (2) 'ulema'an David avdi, and for the sake of my servant David' = the Davidic covenant guarantee (2 Sam 7:12-16: 'I will establish his kingdom forever... his throne will be established forever'). The Davidic covenant is the specific theological basis for Jerusalem's protection (Ps 132:11-18: 'YHWH has sworn an oath to David... here I will set up a horn for David; I have prepared a lamp for my anointed one'). Both motivations — YHWH's own character and the covenant with David — converge on Jerusalem's protection.</p>",
    "36": "<p>'Then the angel of the LORD went out and struck down one hundred and eighty-five thousand in the Assyrian camp. When the survivors arose early in the morning, there were corpses everywhere' — the fulfillment: 'vayyetse malakh YHWH vayakh bemachaneh Ashshur, and the angel of YHWH went out and struck in the Assyrian camp.' The malakh YHWH (angel/messenger of YHWH = the divine agent who executes YHWH's judgments: Exod 12:23, the destroyer at Passover; 2 Sam 24:15-16, the plague-angel). 185,000 killed overnight. Sennacherib's own Annals are significantly silent about why he did not capture Jerusalem — a major city's capture would normally be celebrated in detail. The Greek historian Herodotus (2:141) records an Egyptian tradition that field mice ate the Assyrian bowstrings and leather equipment overnight, forcing retreat — a symbolic account of the same night-disaster. The early morning discovery ('vayashkimu baboqer, and they rose early in the morning') = the unexpected horror of 185,000 corpses where an army had been.</p>",
    "37": "<p>'Then Sennacherib king of Assyria broke camp, returned home, and settled in Nineveh' — the fulfillment of Isaiah's oracle (v7: 'I will put a disturbing spirit in him... and he will return to his own land'): 'vayissa vayyelekh vayashov Sancherib melek Ashshur vayeshev beNinveh, and Sennacherib broke camp and went and returned and settled in Nineveh.' The multiple verbs (broke camp + went + returned + settled) trace the complete withdrawal. Nineveh (on the Tigris, the Assyrian imperial capital, modern Mosul/Kouyunjik, Iraq) was indeed Sennacherib's primary capital — his palace ('Palace Without Rival') has been extensively excavated. The narrative implies no triumphant return but a quiet withdrawal — no captured kings in his wake, no boasting inscription about Jerusalem.</p>",
    "38": "<p>'While he was worshiping in the temple of his god Nisroch, his sons Adrammelech and Sharezer cut him down with the sword and escaped to the land of Ararat. His son Esarhaddon became king in his place' — the assassination fulfilling the second part of Isaiah's oracle (v7: 'I will bring him down by the sword in his own land'): 'vayehi hu mishtachaveh bet Nisroch elohav, and while he was prostrating himself in the temple of Nisroch his god.' Nisroch is attested in Assyrian texts though the exact deity is debated (possibly Nusku, the fire-god, or a corrupted form of another divine name). The sons: Adrammelech (Adad-milki = 'Adad is king') and Sharezer (Nergal-sharezer = 'Nergal protect the king') murdered him in 681 BCE. Babylonian and Assyrian sources confirm the assassination. Esarhaddon (Assur-aha-iddina = 'Ashur has given a brother') succeeded and is historically attested as one of Assyria's most capable rulers (reigned 681-669 BCE). The irony: Sennacherib is killed while worshiping the deity he trusted — in the very temple of his god, his sons murder him.</p>"
  },
  "38": {
    "1": "<p>Isaiah 38:1 introduces the second major crisis of the Hezekiah narrative — the king's illness: 'bayyamim hahem chala Chizkiyahu lamutt, in those days Hezekiah became ill to dying.' The bayamim hahem (in those days) suggests proximity to the Assyrian crisis — the narrative sequence (Assyrian siege → Hezekiah's illness → Babylonian envoys) moves from foreign threat to personal mortality to the pivot toward the Babylonian exile. 'And Isaiah son of Amoz the prophet came to him and said: Thus says the LORD: Set your house in order, for you shall die and will not recover' (ki met attah velo tichyeh, for you are dying and will not live). The initial oracle is death, not life — YHWH's first word is the sentence before the reversal. The 'set your house in order' (tsav leveitekha, give orders to your household = prepare your legal affairs, designate successors, arrange debts and inheritances) is the practical instruction before death.</p>",
    "2": "<p>'Then Hezekiah turned his face to the wall and prayed to the LORD' — the physical posture of prayer: 'vayassov Chizkiyahu panav el-haqqir, and Hezekiah turned his face to the wall.' The turning of the face to the wall: (1) a posture of privacy — prayer away from the officials and visitors in the sickroom; (2) a posture of turning away from the world of the living toward the wall = the threshold of death; (3) a posture of turning toward YHWH — since the wall faced toward the temple in Israelite sacred geography, turning to the wall was turning toward the divine presence. The same root palal (to pray) as in 37:15's 'Hezekiah prayed about Sennacherib' — the same king uses the same prayer-posture for both the national crisis and the personal crisis.</p>",
    "3": "<p>'He prayed: Please, LORD, remember how I have walked before you in faithfulness and with a whole heart, and have done what is good in your sight. And Hezekiah wept bitterly' — Hezekiah's prayer contains two claims: (1) 'asher hithalakhti lefanekhah be'emet uvlev shalem, that I have walked before you in faithfulness and with a whole heart.' The 'walking before YHWH in faithfulness' (emeth, covenant-faithfulness) and 'whole heart' (lev shalem = undivided heart of complete covenant loyalty, cf. 1 Kgs 11:4: Solomon's heart was not fully devoted to YHWH as David's heart had been). (2) 'vehatov be'einekha asiti, and the good in your eyes I have done.' Then: 'vayivkeh Chizkiyahu bekhiyah gedolah, and Hezekiah wept with great weeping.' The weeping (bekhiyah gedolah = great weeping) is unreserved grief — not resignation but vigorous protest and appeal. The prayer argues covenant-faithfulness as the ground for divine response.</p>",
    "4": "<p>'Then the word of the LORD came to Isaiah' — 'vayehi debar-YHWH el-Yesha'yahu, and the word of YHWH came to Isaiah.' The prophetic reception formula: the divine word 'comes to' the prophet (the standard formula for prophetic oracle reception appearing in Jer, Ezek, Hos, Joel, Jon, Mic, Zeph, Hag, Zech). The brevity of this verse emphasizes the immediacy of YHWH's response: the prayer (v3) is immediately followed by the divine word arriving at the prophet (v4), which is immediately followed by the oracle of healing (v5). The speed of response: Hezekiah wept, the word came to Isaiah, Isaiah came with new oracle. The narrative compresses the timeline to convey the urgency of divine response to prayer.</p>",
    "5": "<p>'Go and tell Hezekiah: This is what the LORD says, the God of your father David: I have heard your prayer; I have seen your tears. I will add fifteen years to your life' — the divine reversal: 'halokh ve'amarta el-Chizkiyahu, go and say to Hezekiah.' The oracle identifies YHWH specifically as 'the God of your father David' (Elohei David avikha) = invoking the Davidic covenant as the basis for the healing, just as 37:35 grounded Jerusalem's defense 'for the sake of my servant David.' The three divine acknowledgments: 'samati et-tefillatekhah, I have heard your prayer; ra'iti et-dimatekhah, I have seen your tears; hinneni yosif al-yamekha chamesh esreh shanah, behold I am adding to your days fifteen years.' The divine 'seeing' of tears (dimatekhah) echoes the Exodus-event: 'I have indeed seen the misery of my people' (Exod 3:7). The fifteen additional years are specific and measurable — the covenant God calculates human time.</p>",
    "6": "<p>'I will rescue you and this city from the hand of the king of Assyria, and I will defend this city' — the personal healing linked to the national defense: 'vehitsaltikhah ve'et ha'ir hazot mikkaf melek Ashshur, and I will rescue you and this city from the hand of the king of Assyria.' The oracle connects Hezekiah's personal recovery to Jerusalem's protection — the two crises (personal illness and Assyrian siege) are addressed by the same divine word. The pattern: YHWH who adds 15 years to Hezekiah's life also defends Jerusalem for 15+ years. 'And I will defend this city' (vegeranoti al-ha'ir hazot) = the same formula as 37:35 — the defense of Jerusalem is grounded in both Hezekiah's faithful prayer (38:3) and the Davidic covenant (37:35), with the personal and political inseparably linked.</p>",
    "7": "<p>'And this will be the sign from the LORD to you that the LORD will carry out what he has said' — the sign offered to confirm the oracle: 'vezeh lekha ha'ot me'et YHWH, and this is the sign to you from YHWH.' The 'sign' (ot = a confirming indicator) = the same function as the signs of 7:11-14 (Ahaz's refused sign and the Immanuel sign), 8:18 (Isaiah's children as signs), and 37:30 (the three-year agricultural recovery sign). In each case, the sign both confirms the prophetic word and makes the future event present in the current moment — the shadow reversing on the sundial is the present-tense miracle that guarantees the future promise of healing. YHWH offers signs to accommodate human faith-needs; the sign is not demanded but given freely.</p>",
    "8": "<p>'I will make the shadow on the sundial of Ahaz — the shadow that has already gone down ten steps — go back ten steps. And the sun reversed itself on the steps by ten degrees' — the sundial sign: 'hinneni mashiv et-tsel hama'alot asher yareda bema'alot Achaz, behold I am returning the shadow of the steps that went down on the steps of Ahaz' — 'the sundial of Ahaz' (ma'alot Achaz = the steps/staircase of Ahaz) = a step-sundial or shadow-clock built by Hezekiah's father Ahaz. The shadow going backward (ten steps reversed) = a miraculous reversal of apparent solar movement. 2 Kgs 20:9-11 specifies that Hezekiah was offered a choice: shadow going forward ten steps or backward ten steps; he chose backward as the greater miracle. Whether this was a local atmospheric refraction event, a miraculous suspension of natural law, or a symbolically presented miracle, the sign is clear: YHWH who controls the sun can reverse even time itself. Josh 10:12-14 (the sun standing still at Gibeon) is the other great solar-control miracle.</p>",
    "9": "<p>'The writing of Hezekiah king of Judah, composed after his illness, when he recovered' — the miktav superscription: 'michtav lechizqiyahu melek-Yehudah bachaloto vayechi mechlyayyto, the writing of Hezekiah king of Judah after his being sick, when he recovered from his sickness.' The michtav (written piece = a composition put in writing, a unique title in the OT psalter context; only here; related to kathav = to write). The autobiographical note: this is a royal composition, the only psalm in Isaiah attributed to a specific historical king. The date: 'after his illness, when he recovered' = a thanksgiving-retrospective composed from the other side of the near-death experience. The literary form is the individual thanksgiving psalm: description of distress, cry for help, divine response, vow of praise.</p>",
    "10": "<p>'I said: In the prime of my life I must enter the gates of Sheol, deprived of the rest of my years' — the death-lament of Hezekiah's psalm: 'ani amarti biddemi yamai elekha beshaarei She'ol, I said: in the cutting off of my days I must go to the gates of Sheol.' The demi yamai (the cutting off of my days = the prime/middle of my life, from damam = to be cut off/silenced) — the death coming before the life is complete. 'The gates of Sheol' (sha'arei She'ol = the entrance to the underworld = the point of no return) — Sheol is the OT term for the abode of the dead (equivalent to Hades, the Akkadian Irkalla, the Ugaritic mt realm). 'Deprived of the rest of my years' (puqqadti yeter shenotay, I am deprived of the remainder of my years) — the years that should have remained are taken away prematurely. The lament is not about dying per se but about the incompleteness of death in midlife.</p>",
    "11": "<p>'I said: I will not see the LORD again, even the LORD, in the land of the living; I will gaze on no human face again among those who dwell in the world' — the Sheol-theology of the OT: 'amarti lo-er'eh Yah Yah be'erets hachayim, I said: I will not see Yah, Yah, in the land of the living.' The land of the living (erets hachayim = the realm of the living, contrasted with Sheol) is the place of YHWH-encounter. The double Yah (the shortened divine name) expresses the intensity of the loss. The OT's developed understanding of afterlife is minimal in most pre-exilic texts: Sheol is the shadow-existence where YHWH is not worshiped and cannot be encountered (Ps 6:5; 88:11-12; 115:17). The loss Hezekiah mourns is the loss of the worship-relationship with YHWH — not merely physical death but the ending of covenant fellowship. 'I will gaze on no human face again' (uvadam lo-abit od im-yoshevei chadal, and a human I will not look on among the inhabitants of cessation) = the breaking of all community.</p>",
    "12": "<p>'My home has been pulled up and taken from me like a shepherd's tent; I have rolled up my life like a weaver; he cuts me from the loom. From day to night you bring me to an end' — the three weaving/tent metaphors for life's fragility: (1) 'nissa venistal minni ke'ohel ro'i dori, my dwelling has been pulled up and taken from me like a shepherd's tent' — the shepherd's tent that is packed up and moved instantly, leaving nothing behind. (2) 'qippadti kao'reg chayay, I have rolled up my life like a weaver' — life as a cloth being rolled up at the end of the day's weaving. (3) 'medallah yevazze'eni, he cuts me from the loom' — the finished cloth cut from the loom = death as the severing of the connection between the life-thread and its foundation. 'From day to night you bring me to an end' (miyyom ad-layelah tashlimeni, from day to night you finish me) = the rapid movement from morning vitality to night-death within a single day's span.</p>",
    "13": "<p>'I held on through the night, but like a lion he was crushing all my bones. From day to night you bring me to an end' — the sleepless night of illness: 'shivviti ad-boqer kaarayeh ken yishaber kol-atsmotai, I kept composed until morning — like a lion he was crushing all my bones.' The night of severe illness as the lion's attack: the pain imagined as a great predator crushing bones. Bone-crushing by a lion = the imagery of extreme, physical, inescapable suffering (Job 30:17: 'the night pierces my bones; my gnawing pains never rest'; Ps 22:14-15: 'I am poured out like water, all my bones are out of joint; my heart has turned to wax'). The repeat: 'from day to night you bring me to an end' (miyyom ad-layelah tashlimeni) = the same refrain as v12, creating a rhythmic urgency — each day threatens to be the last.</p>",
    "14": "<p>'Like a swift or a crane, so did I chatter; I moaned like a dove; my eyes grew weary gazing upward. LORD, I am in distress — be my pledge of safety' — the bird-imagery of desperate prayer: 'kesus agur ken atsfatsef, like a swift, like a crane, so I chirped.' The tsaftsuf (to chirp = the thin, high-pitched cry of small birds, the antithesis of the deep, resonant prayer of the worship-assembly). The sick person's prayer reduced to bird-like chirping = the diminishment of voice that illness causes. 'I moaned like a dove' (ehgeh kayonah, I murmured like a dove = the low, throaty cooing of the dove, the sound of grief in ANE poetry, cf. Isa 59:11; Nah 2:7). 'My eyes grew weary gazing upward' (dalleu einai lammarom, my eyes are languid/failing, gazing toward the heights) = physical weakness combined with continued prayer. 'LORD, I am in distress — be my pledge of safety' (YHWH ashaqah li, araveni, LORD I am oppressed; be surety for me) — araveni (be my pledge/surety = the term for a guarantor who takes responsibility for another's debt or safety).</p>",
    "15": "<p>'What can I say? He spoke — and he himself did it. I will walk slowly all my years, weighted down by the bitterness of my soul' — the reversal of the lament into thanksgiving: 'mah-adabber ve'amar li vehu asah, what shall I say — and he said to me — and he himself did it.' The speechlessness of the healed: all the words of lamentation (vv10-14) are rendered insufficient by the divine act of healing. 'I will walk slowly all my years' (eddaddeh kol-shenotai, I will walk carefully/deliberately all my years) = the post-illness posture of deliberate, measured living rather than presuming on time. 'Weighted down by the bitterness of my soul' (al-mar nafshi, over the bitterness of my soul) = the ongoing awareness of having been near death — the bitterness of the illness-experience remains as a productive humility.</p>",
    "16": "<p>'O Lord, by such things people live, and through all these things is the life of my spirit. So restore my health and let me live' — the theological reflection on suffering as life-giving: 'Adonai aleyhem yichyu ulkhol-bahen chayye-ruchi, O Lord, by them people live, and through all of them is the life of my spirit.' The 'such things' (aleyhem) = the things just described: the bitter suffering, the near-death experience, the wrestling in prayer — these are the very experiences through which life deepens. Suffering as pedagogy: not minimized ('it wasn't really that bad') but embraced ('through these very things the spirit lives'). 'So restore my health and let me live' (vetachlimeni vehachayeni, and you have healed me and revived me) — the transition from petition to thanksgiving as the healing is already accomplished in retrospect.</p>",
    "17": "<p>'See — it was for my welfare that I suffered such bitter anguish; but you held my life back from the pit of destruction, and you have cast all my sins behind your back' — the theological interpretation of suffering: 'hineh leshalom mar-li mar, behold for my peace it was very bitter to me' — the paradox of the felix culpa: the bitterness (mar, the bitterness of Marah in Exod 15:23) was for my shalom (peace/welfare). The suffering that produced the shalom is the divine pedagogy of 26:16: 'when your discipline falls on them, they whispered their prayers.' 'You held my life back from the pit of destruction' (vattachshok nafshi mishachat, and you held back my soul from the pit) = the divine restraint that prevented the descent into She'ol. The climax: 'vekhishlaakhta acher gevekhah kol-chetai, and you have cast behind your back all my sins' — the complete forgiveness expressed as the most emphatic possible distance: thrown behind YHWH's back, out of his sight forever (cf. Mic 7:19: 'you will hurl all our iniquities into the depths of the sea').</p>",
    "18": "<p>'For Sheol cannot thank you; death cannot praise you; those who descend to the pit cannot hope in your faithfulness' — the OT pneumatology of Sheol: 'ki lo She'ol todekha, for Sheol cannot thank you.' The three negatives: Sheol cannot give thanks (yadah = the thanksgiving of the worship-assembly), death cannot praise (halal = the hallelujah-praise), those in the pit cannot hope in YHWH's faithfulness (emeth = covenant-faithfulness). This is the pre-resurrection theology of most of the OT: the dead in Sheol are cut off from active worship (Ps 6:5; 30:9; 88:10-12; 115:17). The theological urgency: if only the living can praise, then preserving life is preserving praise. Hezekiah's prayer for life is simultaneously a prayer for continued worship. The NT contrast is stark: Rev 5:13 has 'every creature in heaven and on earth and under the earth' praising — the resurrection breaks the Sheol-silence.</p>",
    "19": "<p>'Only the living, the living, give you thanks — as I do today. A father makes known your faithfulness to his children' — the priority of living praise: 'chay chay hu yodekha kamooni hayyom, the living, the living — he gives thanks to you, as I do today.' The emphatic repetition (chay chay = living, living = double emphasis on the vitality required for true praise). 'As I do today' (kamooni hayyom) = the praise happening in the present moment of Hezekiah's recovered health is the fulfillment of the argument: the living man praises. 'A father makes known your faithfulness to his children' (av el-banim yodi'a el-amittekha, a father to children makes known your faithfulness) = the inter-generational transmission of covenant testimony. The healed person becomes the witness who declares YHWH's faithfulness to the next generation — the living praise extends through time.</p>",
    "20": "<p>'The LORD was ready to save me. And we will play my songs of praise to stringed instruments all the days of our life in the house of the LORD' — the resolution in communal worship: 'YHWH lehoshi'eni, the LORD was ready/resolved to save me.' The lahoshi'eni (to save me = the infinitive construct expressing YHWH's determined purpose) = YHWH's saving was not reluctant or uncertain but resolved. 'And we will play my songs of praise to stringed instruments all the days of our life in the house of the LORD' (unaginnotai nenaggein kol-yemei chayyenu al-beit YHWH, and my songs of praise we will play on stringed instruments all the days of our life in the house of YHWH). The singular ('my songs') becomes plural ('we will play') = the personal thanksgiving becoming communal worship. The 'house of the LORD' (beit YHWH) = the temple as the permanent site of the ongoing praise that Sheol cannot give but the living community can.</p>",
    "21": "<p>'Now Isaiah had said, Let them take a pressed cake of figs and apply it as a poultice on the sore, and he will recover' — the medical treatment: 'vayomer Yesha'yahu yisse'u deveylat te'enim, and Isaiah had said: let them take a lump of pressed figs.' The deveilat te'enim (a pressed-fig cake/poultice) = figs pressed into a mass, used as a poultice on skin infections and wounds. Fig poultices had known medicinal uses in the ANE — the warm, moist application was thought to draw out infection (modern research suggests figs have some anti-inflammatory properties). 'And apply it on the sore, and he will recover' (veyimrach al-hashchin veichyeh) — the 'sore' (shchin = an inflamed/festering sore, the same word as the Egyptian boils of Exod 9:9-10; Job 2:7). The theological point: YHWH's healing works through the natural medicine provided. This is the pattern throughout OT healing: 2 Kgs 5:10 (Elisha tells Naaman to wash in the Jordan); John 9:6 (Jesus makes mud for the blind man's eyes) — divine healing and natural means working together.</p>",
    "22": "<p>'And Hezekiah had asked, What will be the sign that I shall go up to the house of the LORD?' — the sign-request for temple access: 'vayomer Chizkiyahu mah ot ki e'aleh beit YHWH, and Hezekiah said: what is the sign that I shall go up to the house of YHWH?' The request is for assurance that the healing will be complete enough to allow pilgrimage to the temple — the temple-visit as the marker of restored covenant fellowship. The question appears here as an appendix (2 Kgs 20:8 places it earlier in the narrative) — Isaiah provides the sundial sign (v8) as the answer to this request for a sign. The temple-visit as recovery-goal: Hezekiah's concern is not merely physical health but restoration of the worship-relationship with YHWH that illness had interrupted.</p>"
  },
  "39": {
    "1": "<p>Isaiah 39:1 introduces the Babylonian envoys who are the pivot between the historical narrative of chs.36-38 and the exile-comfort of chs.40-66: 'baet hahi shalach Merodach-baladan ben-Baladan melek Bavel, at that time Merodach-baladan son of Baladan king of Babylon sent.' Merodach-baladan (Marduk-apla-iddina II in Akkadian) was the Chaldean tribal chief who twice seized Babylon against Assyrian control: 721-710 BCE (during Sargon II's reign) and briefly in 703 BCE (during Sennacherib's early reign). He was a persistent anti-Assyrian resistance leader who sought alliances with western states (including Egypt, Judah, and Elam) to build a coalition against Assyria. His sending of 'letters and a gift' (sefarim umminchah, letters and a gift-offering) to Hezekiah was diplomatically motivated: 'because he had heard that he had been sick and had recovered' — the recovery from illness provided the diplomatic occasion for an alliance-building embassy.</p>",
    "2": "<p>'Hezekiah received them gladly and showed them the storehouse of his treasures' — the fatal pride: 'vayishmach aleihem Chizkiyahu, and Hezekiah rejoiced/was glad over them.' The vayishmach (he was glad = the verb of joyful reception) signals the theological problem: Hezekiah's gladness is in the international attention, not in YHWH who had just saved him from both Sennacherib and his own death. 'He showed them the house of his treasures' (vayar'em et-beit nekhoto, and he showed them his house of precious things) — the entire wealth of the kingdom displayed: 'the silver, the gold, the spices, the fine oil, his entire armory, everything found in his storerooms; there was nothing in his palace or in all his realm that Hezekiah did not show them.' The comprehensive display (nothing not shown) is the precise opposite of the appropriate reserve. Hezekiah uses the occasion of the recovery-visit to show off the kingdom's wealth to a potential military ally — the same strategic calculation (seeking human alliance) that Isaiah had condemned in the Egypt-alliance oracles of chs. 30-31.</p>",
    "3": "<p>'Then the prophet Isaiah came to King Hezekiah and asked him: What did these men say, and where did they come from?' — the prophetic interrogation: 'vayyavo Yesha'yahu hannavi el-hammelek Chizkiyahu, and Isaiah the prophet came to King Hezekiah.' Unlike the previous interactions (where Hezekiah sent to Isaiah), here Isaiah comes uninvited — the prophet initiates the confrontation. 'What did these men say?' (mah amru ha'anashim ha'elleh, what did these men say?) and 'where did they come from?' (ume'ayin yavo'u eleykha, and from where did they come to you?) — two simple questions that invite Hezekiah's self-incriminating answer. 'They came from a far country — from Babylon' (meerets rechokah bau mimBavel, from a far land they came, from Babylon) — the 'far country' (erets rechokah) echoes the 'LORD comes from far away' of 30:27 (YHWH's approach) but here it is the enemy who comes from far away. Babylon was approximately 900 miles from Jerusalem.</p>",
    "4": "<p>'Isaiah asked: What have they seen in your palace? Hezekiah answered: They have seen everything. There is nothing in my storehouses that I did not show them' — the self-revelation: 'mah rau beveitekha, what did they see in your house?' The simple question exposes the full extent of the indiscretion. 'Everything' (et-kol asher beveyti, everything that is in my house) — the categorical 'everything' is the problem. No diplomatic reserve, no selective disclosure — the entire kingdom's strategic and material assets revealed to a foreign power. 'There is nothing in my storehouses that I did not show them' (lo-hiyah davar asher lo-hare'itim beotsrotai, there was nothing I did not show them in my treasuries) — the emphatic double negative makes the completeness of the disclosure absolute. The king has given the enemy complete strategic intelligence of his kingdom's resources.</p>",
    "5": "<p>'Then Isaiah said to Hezekiah: Hear the word of the LORD of hosts' — the prophetic announcement of judgment: 'vayomer Yesha'yahu el-Chizkiyahu shema debar-YHWH tseva'ot, and Isaiah said to Hezekiah: hear the word of YHWH of hosts.' The 'hear the word of the LORD' (shema debar-YHWH) = the formal prophetic announcement-formula that introduces a divine oracle (1 Kgs 22:19; Jer 2:4; 7:2; 17:20; 19:3; Amos 7:16). The use of YHWH tseva'ot (YHWH of hosts = YHWH of armies, the divine warrior title) in this context of a military-political blunder is pointed: the God of armies is about to announce the consequence of trusting in a foreign army's diplomacy rather than in YHWH of armies.</p>",
    "6": "<p>'Watch — days are coming when everything in your palace, everything your ancestors stored up until today, will be carried off to Babylon. Nothing will be left, declares the LORD' — the Babylonian exile predicted: 'hineh yamim ba'im venissa kol-asher beveitekha, behold days are coming and all that is in your house will be carried away.' The hineh yamim ba'im (behold days are coming = the standard prophetic introduction of a future oracle of doom, appearing in Jer 7:32; 9:25; 31:27-38; Amos 4:2; 8:11) introduces the exile oracle. 'Everything your ancestors stored up until today' (ve'et asher aseru avoteykha ad-hayyom hazeh, and what your fathers stored up until this day) = the cumulative wealth of the Davidic dynasty, generations of accumulation — all will be taken. 'Carried off to Babylon' (elBavel yubbel) = the specific destination. This prediction, made in the Assyrian period (701 BCE), points nearly 115 years into the future (586 BCE) to the Babylonian destruction of Jerusalem — the theological bridge between First and Second Isaiah.</p>",
    "7": "<p>'And some of your own sons — your own descendants, whom you will father — will be taken away and serve as court officials in the palace of the king of Babylon' — the deportation of the royal family: 'umibbanekha asher yets'u mimmmekha, and from your sons who will come from you.' 'Whom you will father' (asher tolid) = not yet born at the time of the oracle. 'Will be taken away and become eunuchs' (yuqqachu vehayu sarisim, they will be taken and will be court officials/eunuchs in the palace of the king of Babylon). The saris (court official/eunuch = the castrated male courtiers who served in Babylonian royal courts; the practice was common in ANE palace administration). Dan 1:3-7 narrates the fulfillment: 'the king told Ashpenaz, his chief official, to bring some of the Israelites from the royal family and the nobility — young men without any physical defect, handsome, showing aptitude for learning' — Daniel, Hananiah, Mishael, and Azariah among them.</p>",
    "8": "<p>'Then Hezekiah said to Isaiah: The word of the LORD that you have spoken is good. And he added: At least there will be peace and security during my own lifetime' — Hezekiah's disturbing acceptance: 'vayomer Chizkiyahu el-Yesha'yahu tov davar-YHWH asher dibbart, and Hezekiah said to Isaiah: the word of YHWH which you have spoken is good.' The acceptance of the oracle as 'good' (tov = the standard of divine evaluation from Gen 1) shows Hezekiah's submission to prophetic authority. But the second clause complicates it: 'ki yehi shalom ve'emet biyamai, for there will be peace and truth in my days.' The 'at least in my own lifetime' = a narrow self-concern that contrasts sharply with Hezekiah's earlier prayer 'so that all the kingdoms of the earth may know that you, LORD, are God' (37:20). There, the prayer was universal; here, the concern is personal. Many interpreters read this as a moral failure; others read it as resigned acceptance of divine decree. In either case, it pivots the narrative toward the exile-comfort of chs.40-66.</p>"
  },
  "40": {
    "1": "<p>Isaiah 40:1 opens the second major section of Isaiah (chs.40-66) with the most famous comfort-oracle in the OT: 'Nachamu nachamu ammi yomar Eloheikhem, Comfort, comfort my people, says your God.' The double nachamu (comfort, comfort = the double imperative of urgency and intensity, matching the double 'chaos and void' of Gen 1:2 that this section will reverse) is addressed to unspecified heralds ('nachamu' is masculine plural = comfort! [you all]). The theological pivot: ch.39 ends with the Babylonian exile decreed; ch.40 begins with comfort for the exiles. The gap between the decree (39:6-7) and the comfort (40:1) is the exile itself — the narrative leaps over the 115 years of Israel's history between 701 BCE and 586 BCE to address the community already in exile. 'My people' (ammi) = the covenant relationship still intact despite the exile; 'your God' (Eloheikhem) = the covenant formula maintained.</p>",
    "2": "<p>'Speak tenderly to Jerusalem and declare to her that her time of service is ended, that her iniquity is pardoned, that she has received from the LORD's hand double for all her sins' — the three declarations of comfort: 'dabber al-lev Yerushalayim, speak to the heart of Jerusalem' (the intimate speech of a comforting parent or spouse — the same 'speaking to the heart' as Gen 34:3 when Shechem spoke tenderly to Dinah; Hos 2:14 when YHWH speaks tenderly to Israel in the wilderness). (1) 'ki maleah tseva'ah, for her hard service is completed' (tsava = military/forced service, the conscripted labor of the exile); (2) 'ki nirtsah avonah, for her iniquity is pardoned/accepted' (nirtsah from ratsah = to be pleased with, to accept — the exile has been the atonement for the sin, YHWH now 'accepting' it as complete); (3) 'ki laqechah miyyad YHWH kiflayim bechol-chataoteiyha, for she has received from YHWH's hand double for all her sins' — the kiflayim (double = a full, complete measure; the legal payment of double for theft, Exod 22:7).</p>",
    "3": "<p>'A voice cries in the wilderness: Prepare the way of the LORD; make straight in the desert a highway for our God' — the herald's command for the divine processional road: 'qol qore bamidbar, a voice crying in the wilderness.' The unidentified 'voice' (qol) calling in the wilderness. The command: 'panu derekh YHWH, yasshiru ba'aravah mesillah le'Elohenu, prepare the way of YHWH; make level in the desert a highway for our God.' The ANE royal road-preparation: before a king traveled, his advance team would level the road, fill potholes, smooth rough sections. The wilderness/desert as the terrain: the return from Babylon would traverse the Syrian desert. The theological dimension: YHWH himself is coming to lead his people home, and the road is prepared for the divine warrior-shepherd. All four Gospels apply v.3 to John the Baptist (Matt 3:3; Mark 1:3; Luke 3:4; John 1:23): he is the 'voice crying in the wilderness' preparing the way for Jesus.</p>",
    "4": "<p>'Every valley will be raised up and every mountain and hill leveled; the crooked will be made straight and the rough ground a plain' — the cosmic road-preparation: 'kol-gey yinnase vekhol-har vegiv'ah yishpalu, every valley will be lifted up and every mountain and hill will be leveled.' The radical terraforming: valleys raised (the low places of depression elevated), mountains leveled (the high barriers removed), crooked made straight (the devious paths straightened), rough ground smoothed. This is not merely topographical but theological: the obstacles between the exiles and their God are removed. Luke 3:5-6 quotes the full version, extending to 'all flesh will see God's salvation' (Isa 40:5). The theology of the prepared road: YHWH does not require his people to navigate the obstacles; he clears them. Grace precedes the journey.</p>",
    "5": "<p>'The glory of the LORD will be revealed, and all flesh will see it together; for the mouth of the LORD has spoken' — the purpose and guarantee of the preparation: 'venighah kevod YHWH vera'u khol-basar yachdav, and the glory of YHWH will be revealed and all flesh will see it together.' The kavod (glory = the radiant presence-manifestation of YHWH, the shekinah-glory of Exod 16:10; 24:16-17; 40:34-35 when YHWH's cloud-glory filled the tabernacle). 'All flesh together' (kol-basar yachdav = every human being simultaneously) = the universal, simultaneous revelation of YHWH's glory in the new Exodus event. The guarantee: 'ki pi YHWH dibber, for the mouth of YHWH has spoken' — the prophetic authentication formula. YHWH's speech is the guarantee of the event: his word creates what it declares (Gen 1: 'God said... and there was').</p>",
    "6": "<p>'A voice says, Cry! And someone asks, What shall I cry? All flesh is grass, and all its beauty is like the flower of the field' — the herald's commission and the human-transience message: 'qol omer qera, a voice says: cry out.' A different 'voice' from v3 now gives the second command. 'And he says, What shall I cry?' (veyomar mah aqra, and the one commanded says: what shall I cry?) — the dialogic form: the commissioned herald asks for content. The content: 'kol-habasar chatsir vekol-chasdoh ke'tsits hassadeh, all flesh is grass and all its faithfulness/beauty is like the flower of the field.' The chatsir (grass/hay) and tsits hassadeh (flower of the field) = the vegetation that is beautiful in its brief flowering but rapidly fades. 1 Pet 1:24-25 quotes vv.6-8 directly: 'All flesh is like grass and all human glory is like the flower of the field; the grass withers and the flower falls, but the word of the Lord endures forever.'</p>",
    "7": "<p>'The grass withers and the flower fades when the breath of the LORD blows on them; the people are surely grass' — the mechanism of human transience: 'yavesh chatsir naval tsits ki ruach YHWH nashevah bo, the grass withers, the flower fades, for the breath of YHWH blows on them.' The ruach YHWH (the breath/spirit/wind of YHWH) is the divine wind that in Gen 1:2 'hovered over the waters' and in Gen 2:7 'breathed into man's nostrils the breath of life.' The same divine breath that creates life also, when blown, withers the grass of human pretension. 'The people are surely grass' (aken chatsir ha'am, certainly the people are grass) — the emphatic aken (surely/certainly) applies the botanical metaphor directly to human beings. All the royal pride, military power, and accumulated wealth of the nations that oppose YHWH are as durable as summer grass under a scorching wind.</p>",
    "8": "<p>'The grass withers, the flower fades, but the word of our God stands forever' — the central contrast of the herald's message: 'yavesh chatsir naval tsits, udvar Elohenu yaqum le'olam, the grass withers, the flower fades, but the word of our God stands forever.' The contrast could not be sharper: the transient (grass, flower) vs. the permanent (YHWH's word). The 'word of our God' (dvar Elohenu = the prophetic-covenantal word, the creative word of Gen 1, the Torah, and the specific promises of 40:1-5) 'stands forever' (yaqum le'olam = rises/stands to the age = is permanently established). The comfort for the exiles who have watched everything human collapse (Jerusalem, the temple, the Davidic monarchy, the national identity) is that the divine word remains. What was promised remains promised; what was guaranteed remains guaranteed despite the collapse of every human institution.</p>",
    "9": "<p>'Get up onto a high mountain, O Zion, messenger of good news! Lift your voice with strength, O Jerusalem, herald of good news! Lift it up; do not fear! Say to the cities of Judah: Look — your God!' — the herald's proclamation to Zion: 'al-har-gavoah ali-lakh mevasseret Tsiyon, onto a high mountain go up for yourself, herald of Zion.' The mevasseret (herald of good news = from bissar = to bring good news, the root of the NT euangelion/gospel). Zion is the herald who proclaims the good news to the cities of Judah. 'Lift your voice with strength' (harimi vekoach qolekh mevasseret Yerushalayim, lift up your voice with strength, herald of Jerusalem). 'Do not fear' (al-tira'i) = the standard comfort formula now applied to the community-herald. The content of the proclamation: 'hineh Eloheikhem, behold your God!' — the recognition formula: the God who has returned is the covenant God ('your God'), not an abstract divine principle. The heralding of YHWH's return is the first gospel.</p>",
    "10": "<p>'See — the Lord GOD comes with strength, and his arm rules on his behalf; see — his reward is with him, and his recompense before him' — the divine warrior's arrival: 'hineh Adonai YHWH bechazaq yavo uzerou moshelah lo, behold the Lord YHWH comes with strength, and his arm rules for him.' The divine warrior's arm (zero'ah = the arm of strength, the instrument of the Exodus: Exod 6:6; Deut 4:34; 5:15; 26:8) rules 'for him' (lo = on his behalf). 'His reward is with him' (hineh sekharo itto, behold his wage/reward is with him) = the wages YHWH pays to his redeemed: the return from exile, the restoration of covenant fellowship, the multiplication of blessing. 'And his recompense before him' (upe'ulato lefanaiv, and his work/recompense before him) — the divine warrior both brings the reward to his people and carries the recompense for the enemies before him as he advances.</p>",
    "11": "<p>'He tends his flock like a shepherd; he gathers the lambs in his arm and carries them in his bosom; he gently leads the nursing ewes' — the divine shepherd: 'kero'eh edro yir'eh, like a shepherd he tends his flock.' The warrior of v10 is immediately revealed as the shepherd of v11 — the two images held together describe the one God who fights for his people and tenderly cares for the weak. 'He gathers the lambs in his arm' (bizeroo yiqabbets telaim, in his arm he gathers the lambs) — the arm (zero'ah) that is the instrument of the warrior (v10) is the same arm that gathers the vulnerable lambs. 'Carries them in his bosom' (uvecheiqo yissa, and carries them in his bosom/breast) — the intimate carrying of an infant. 'Gently leads the nursing ewes' (allot yenachel = the nursing ewes, the mothers with young, he will gently lead) — the most vulnerable part of the flock (nursing mothers with lambs) receive the most careful guidance. John 10:11-14 makes the 'Good Shepherd' imagery explicit in Jesus; John 10:27-29 has Jesus carrying his sheep securely.</p>",
    "12": "<p>'Who has measured the waters in the hollow of his hand, marked off the heavens with a span, gathered up the dust of the earth in a measure, weighed the mountains in scales and the hills in a balance?' — the incomparability hymn's five creation-mastery questions: (1) 'mi-madad veshipchulelo mayim, who has measured the waters in the hollow of his hand?' — the world's oceans held in a cupped palm; (2) 'vesamayim bazzeret tikken, and the heavens he measured with a span?' — the span (zereth = the hand-width from thumb to little finger) measuring the entire sky; (3) 'vekhal beshalis afer ha'arets, and the dust of the earth in a third-measure?' — the world's soil measured in a one-third unit; (4) 'veshaqal behapeles harim, and weighed the mountains in scales?' — the Himalayan and Alpine ranges in a weighing balance; (5) 'ugevaot bemozenayim, and the hills in a balance?' — the hills in a merchant's scale. All five questions expect the same answer: no one but YHWH. The rhetorical questions establish the category difference between YHWH and all created powers.</p>",
    "13": "<p>'Who has guided the Spirit of the LORD, or who has been his counselor to instruct him?' — the divine self-sufficiency in wisdom: 'mi-tikken et-ruach YHWH, who has directed/measured the Spirit of YHWH?' The tikken (measured/directed = from tikken = to establish/measure, the same root as the measuring of v12) applied to YHWH's ruach = no one can direct or measure the divine Spirit. The parallel: 'veish atsato yodi'enu, and a man of his counsel to instruct him?' — no human advisor is in YHWH's council to instruct him. Paul quotes v13 in Rom 11:34: 'Who has known the mind of the Lord? Or who has been his counselor?' — and in 1 Cor 2:16: 'Who has known the mind of the Lord so as to instruct him? But we have the mind of Christ.' The Johannine Logos-theology and Pauline Christology both draw on this verse to explain how the pre-existent wisdom/word of YHWH could be incarnate in Jesus.</p>",
    "14": "<p>'With whom did he consult? Who instructed him and taught him the path of justice, who taught him knowledge and showed him the way of understanding?' — the four wisdom-attributes YHWH possesses independently: (1) mishpat (the path of justice), (2) da'at (knowledge), (3) tevunah (the way of understanding/discernment). No one taught YHWH any of these — he possesses them as intrinsic attributes of his nature, not as acquired learning. The theological implication for the exiles: the God who brings them comfort is not learning or improvising as he goes. His rescue plan is not reactive but based on complete wisdom ('plans formed long ago,' 25:1). The incomparability of YHWH's wisdom contrasts with the 'wisdom of the wise' that will perish (29:14) and the 'wisdom of Egypt' that is worthless (31:2).</p>",
    "15": "<p>'See — the nations are like a drop in a bucket and are counted as dust on the scales; see — he lifts up the coastlands like a grain of fine dust' — the nations' insignificance before the creator: 'hen goyim kemar meddeli, behold the nations are like a drop from a bucket.' The mar meddeli (a drop from a bucket = the water droplet on the outside of a bucket after it has been dipped = the most insignificant possible residue). 'And counted as dust on the scales' (ucheshab avaq moznayim, and accounted as fine dust of the scales = the weightless fine powder that settles on the balance-pans between weighings). 'He lifts up the coastlands like a grain of fine dust' (hen iyyim kaddiq yittol, the coastlands he lifts up like a very fine thing) — the Mediterranean coastlands (the entire western horizon of the ANE political world) = a grain of fine dust lifted by YHWH. The nations that Sennacherib boasted of conquering are weightless specks before their creator.</p>",
    "16": "<p>'Even Lebanon is not sufficient for firewood, nor are its animals enough for a burnt offering' — the transcendence of YHWH beyond adequate worship: 'uLevanon ein dai ber, and Lebanon is not sufficient for fuel.' Lebanon (the great cedar-forest whose timber was the most prized in the ANE — used for Solomon's temple, 1 Kgs 5; Sennacherib's boast in 37:24 about cutting its cedars) would not provide enough wood to burn an adequate offering to YHWH. 'Nor are its animals enough for a burnt offering' (vechayato ein dei olah, and its animals are not sufficient for a burnt offering). The entire forested mountain and its abundant wildlife cannot provide a sacrifice worthy of YHWH. The logic: if all of Lebanon's timber and animals cannot adequately honor YHWH, then no physical sacrifice — however grand — can encompass his worth. This is not an attack on sacrifice but an affirmation of YHWH's incomparable transcendence.</p>",
    "17": "<p>'All the nations are as nothing before him; they are counted by him as less than nothing and futility' — the superlative of insignificance: 'kol-hagoyim ke'ayin negdo, all the nations are as nothing before him.' The ke'ayin (as nothing = like non-being, like the ayin that is the absence of existence) — the most extreme possible statement of insignificance. 'They are counted by him as less than nothing and futility' (me'efes uvohu nechshevoo lo, from nothing and chaos they are reckoned to him). The me'efes (from nothing = less than zero) and tohu (chaos/void = the tohu of Gen 1:2) — the nations in YHWH's accounting are below zero, less than the pre-creation chaos. This is not contempt for human beings but a systematic demonstration of the infinite category-difference between the creator and any collection of creatures. Against the Babylonian imperial theology that treated nations as components of a divine order, YHWH is categorically above and beyond the entire national system.</p>",
    "18": "<p>'To whom will you compare God? What likeness will you set beside him?' — the incomparability question as the threshold of the idol polemic: 've'el-mi tedamyun El umah-demut ta'arkhu lo, and to whom will you liken God, and what comparison will you set beside him?' The central question of the entire incomparability section (vv.12-26). The 'likeness' (demuth = the image/resemblance, the same word as Gen 1:26: 'let us make humanity in our image and likeness') = what comparison class does YHWH belong to? The answer: none. He is sui generis — without comparison. The rhetorical question opens into the idol polemic (vv.19-20) which provides the false answer (an idol) and then exposes its absurdity. The same incomparability question returns in v.25 ('To whom will you compare me? Who is my equal? says the Holy One').</p>",
    "19": "<p>'A craftsman casts an idol, and the goldsmith overlays it with gold and fashions silver chains for it' — the idol-making process analyzed: 'happesel nassakh charash, the craftsman has poured out/cast an idol.' The pesel (the idol, from pasal = to hew/carve) made by the charash (the craftsman/smith = the skilled metalworker). The goldsmith (tsaref) overlays it with gold (yetsappenhu zahav, he covers it with gold) and fashions chains of silver (uretuqot keseph yetsarref, silver chains he works). The contrast: YHWH 'created the heavens and the earth' (v12-17's implied creator of all creation) vs. the craftsman who takes created materials (gold, silver) and manufactures a decorated object. The creator of gold vs. an object covered with gold = the absurdity of confusing the creator with a precious-metal-covered wooden/stone form. Isaiah 44:9-20 develops the idol-polemic to its most extended satirical form.</p>",
    "20": "<p>'He who is too poor to bring a proper offering selects wood that will not rot; he looks for a skilled craftsman to set up an idol that will not topple' — the poor man's idol: 'hamseukan terumah ets lo-yirqav yivchar, the one who is too poor for an offering — wood that will not rot he chooses.' The 'poor man's idol': even the person who cannot afford gold or silver wants an idol, so he selects good-quality wood (that will resist decay) rather than precious metals. 'He seeks a skilled craftsman' (charash chakham yevaqesh-lo, he seeks for himself a skilled craftsman) 'to set up an idol that will not topple' (hakhim pesel bilthi yimot, to set up a carved image so it will not topple). The irony: the craftsman's primary technical challenge is making the idol stand up without falling — a deity whose main quality is structural stability. The 'idol that won't topple' becomes a marker of divine weakness: YHWH holds the heavens in place; this deity needs a craftsman to ensure it doesn't fall over.</p>",
    "21": "<p>'Do you not know? Have you not heard? Has it not been declared to you from the beginning? Have you not understood from the foundations of the earth?' — the four rhetorical questions of prophetic pedagogy: (1) 'halo tede'u, do you not know?' (2) 'halo tishme'u, do you not hear?' (3) 'halo huggad mero'sh lakhem, has it not been declared to you from the beginning?' (4) 'halo havvinu mosdot ha'arets, have you not understood the foundations of the earth?' The four questions bracket human knowing: active knowledge (know), receptive knowledge (hear), revealed knowledge (declared), foundational knowledge (from the earth's foundations). The implied answer to all four: yes, it has been known, heard, declared, and foundationally available — the exiles have access to this knowledge, they have simply failed to apply it. The teaching that follows (vv.22-26) supplies the content they should already know.</p>",
    "22": "<p>'It is he who sits enthroned above the circle of the earth, whose inhabitants are like grasshoppers; who stretches out the heavens like a curtain and spreads them like a tent to live in' — YHWH's cosmic governance: 'haggoisher al-chug ha'arets veyyosheveyha kechaggavim, he who sits above the circle/disk of the earth, and its inhabitants are like grasshoppers.' The chug (circle = the disk or vault of the sky or earth, from chug = to draw a circle; also Job 22:14: 'he walks in the vault of heaven'; Prov 8:27: 'when he inscribed a circle on the face of the deep'). The inhabitants as grasshoppers (chaggavim = locusts/grasshoppers) = the perspective from YHWH's cosmic height makes even the massed nations look like insects. 'He stretches out the heavens like a curtain' (hannotteh kashaqqim shamayim, the one who spreads out the heavens like a thin curtain/veil) and 'spreads them like a tent' (vayimtahem kaohel lasheveth, and stretches them out as a tent for dwelling) = the creation-imagery of the sky as YHWH's dwelling-tent (Ps 104:2-3).</p>",
    "23": "<p>'He brings princes to nothing and reduces the rulers of the earth to emptiness' — the divine reversal of political power: 'hannoten rozenim la'ayin, he gives princes to nothingness.' The rozenim (the rulers/princes = those who deliberate in council, the senior governmental figures) are given 'to nothingness' (la'ayin = to the non-being of v17). The parallel: 'shofetei erets kehahu asah, judges/rulers of the earth like a chaos/void he makes them.' The tohu (chaos/void = the Gen 1:2 pre-creation state) applied to earthly rulers — YHWH reduces the great to the condition of pre-creation. This is the Day-of-the-LORD theology (2:11-17: 'the loftiness of man will be bowed down, and the haughtiness of men will be humbled') applied to the Babylonian empire that held Israel in exile.</p>",
    "24": "<p>'Scarcely have they been planted, scarcely sown, their root scarcely taken in the earth, when he blows on them and they wither, and the whirlwind sweeps them away like chaff' — the rapid dissolution of earthly power: 'af bilthi-nittanu af bilthi-zurou af bilthi-sherash ba'aretz giz'am, scarcely planted, scarcely sown, scarcely their stem rooted in the earth.' The three 'scarcely' (af bilthi, even/also not yet) = the three stages of plant growth (planted, sown from seed, root-established) all barely reached before the ending comes. 'And he blows on them and they wither' (veyiggash bahem vayyiveshu, and he blows on them and they wither) — the divine breath (neshimah/ruach = YHWH's blowing) as the withering agent (v7: 'the breath of YHWH blows on them; the people are surely grass'). 'The whirlwind sweeps them away like chaff' (useara kaqash yissaem, like chaff a whirlwind takes them) — the final dissolution: not gradually decaying but suddenly swept away.</p>",
    "25": "<p>'To whom will you compare me? Who is my equal? says the Holy One' — the incomparability question repeated with self-affirmation: 'veal-mi tedamyeuni ve'eshveh yomar qadosh, to whom will you liken me, and I am equal? says the Holy One.' The first incomparability question (v18) asked from outside; now the Holy One (qadosh = YHWH in his distinct, set-apart uniqueness, Isaiah's distinctive title) asks it himself from within — the divine self-assertion. The 'Holy One' without the usual 'of Israel' = the absolute holiness of YHWH in his own being, not merely as Israel's covenant God. The question 've'eshveh, and I am equal to?' expects the same answer as all the preceding rhetorical questions: nothing and no one.</p>",
    "26": "<p>'Lift up your eyes on high and see: who created all these? He leads out their army by number, calling each one by name. Because of his great power and mighty strength, not one of them is missing' — the night-sky as proof of YHWH's incomparability: 'se'u marom eineikhem ur'u mi-vara elleh, lift up your eyes on high and see: who created these?' The starry night sky as the answer to the incomparability question. The stars as YHWH's army: 'hamotsi bemissphar tseva'am lekhullam beshem yiqra, who brings out by number their host, calls them all by name.' The Babylonian astrology assigned divine powers and names to stars — the zodiac as a divine system governing human fate. Isaiah's counter-theology: YHWH is not a star; he calls the stars by name as a military commander calls his troops. 'Not one of them is missing' (ish lo ne'dar, not one is absent) = YHWH's control over the stars is total — perfect military discipline. The exiles in Babylon, surrounded by star-worship, are shown that the stars they see are YHWH's army, not their masters.</p>",
    "27": "<p>'Why do you say, O Jacob, and why do you speak, O Israel: My way is hidden from the LORD, and my cause is overlooked by my God?' — the complaint of divine hiddenness addressed: 'lamah tomar Ya'aqov utedabber Yisrael, why do you say, Jacob, and speak, Israel?' The double name (Jacob/Israel = the covenantal and national identity simultaneously) addressed in the complaint: 'nistarah darkhi meYHWH, my way is hidden from YHWH.' The hidden way (derekh nistar = the path that YHWH cannot see) = the exilic complaint that YHWH has lost track of them in Babylon. 'And my justice/cause is overlooked by my God' (umishpati me'Elohay ya'avor, and my legal cause passes by my God unnoticed). The legal complaint: mishpat (the legal case/right) that YHWH has missed. The exiles feel invisible — their suffering unobserved, their legal claim forgotten. The rhetorical question ('why do you say?') implies the complaint is incorrect, and vv.28-31 provide the correction.</p>",
    "28": "<p>'Do you not know? Have you not heard? The LORD is the everlasting God, the Creator of the ends of the earth. He does not grow faint or weary; his understanding cannot be searched out' — the correction of the hiddenness-complaint with the doctrine of divine eternity and inexhaustibility: 'halo yadatah im-lo shamata, do you not know, or have you not heard?' The same two rhetorical questions as v21 — the exiles are being reminded of what they should already know. 'YHWH Elohei olam bore qetsot ha'arets, YHWH is the God of eternity, the creator of the ends of the earth.' The olam (eternity/everlasting) applied to YHWH = he is not subject to the time-limitations that cause human beings to forget or become exhausted. 'He does not grow faint or weary' (lo yiy'af velo yiga, he does not faint and does not grow weary) — unlike the human beings who grow faint (v29-30), YHWH is exempt from fatigue. 'His understanding cannot be searched out' (ve'en cheqer livunato, and there is no searching out of his understanding) = the divine wisdom is inexhaustible.</p>",
    "29": "<p>'He gives strength to the weary and increases the power of those who have no might' — the transfer of divine strength to the exhausted: 'noten laye'ef koach, he gives to the weary strength.' The noten (he gives = continuous present action, not a past event) characterizes YHWH's ongoing sustaining of the weak. The ye'ef (weary/faint = those exhausted by the demands of the exile, the sustained suffering of displacement) receive koach (strength = the capacity for effective action). 'And increases the power of those who have no might' (ulein onim atsumah yarbeh, and to those without strength he multiplies power). The 'no might' (ein onim = literally 'there is no strength') = those at absolute zero of energy, the completely depleted. YHWH multiplies (yarbeh = increases, makes many) their power. The theological mechanism: the divine inexhaustibility (v28: 'he does not grow faint or weary') transfers to the human community. What YHWH has without limit, he gives to those who have run out.</p>",
    "30": "<p>'Even youths grow faint and weary, and young men stumble and fall' — the contrast with human energy at its peak: 'veyif'u ne'arim veyig'au vebahurim kashol yikashelu, even the young men faint and grow weary, and the young warriors stumble and fall.' The ne'arim (youths = the young men at peak physical condition) and bahurim (the choice young men = the military-age male at peak fitness) both faint and stumble. The ba-hurim kashol yikashelu (the choice young men will stumble, stumbling) = the absolute infinitive creating emphatic certainty. Human energy is finite — even the strongest, fittest, most vital humans eventually run out. This is not pessimism but the realistic diagnosis that enables the promise of v31: the only alternative to eventual exhaustion is receiving strength from the inexhaustible God.</p>",
    "31": "<p>'But those who wait for the LORD will renew their strength; they will soar on wings like eagles; they will run and not grow weary; they will walk and not faint' — the climax of the Comfort Oracle: 'vequvei YHWH yachaliphu koach, but those who wait/hope in YHWH will renew their strength.' The qavah (to wait/hope = from the root meaning 'cord/thread' — those who are tethered to YHWH by the cord of hope and patient expectation). 'Will renew their strength' (yachaliphu koach = will exchange/renew strength) — the chalaf (to exchange/replace/renew = to exchange depleted strength for fresh strength from YHWH). Three levels of movement: 'they will soar on wings like eagles' (ya'alu ever kaneshrim, they will mount up with wings like eagles = the highest, most effortless movement); 'they will run and not grow weary' (yarutsu velo yig'au, they will run and not be weary = sustained effort without fatigue); 'they will walk and not faint' (yelekhu velo yiy'afu, they will walk and not faint = the ordinary, plodding, day-to-day perseverance without exhaustion). The descending order (soar → run → walk) may be intentional: the most dramatic manifestation is easiest; the ordinary walk without fainting is the deepest spiritual achievement.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
